:root{
  --bg: #000000;
  --boid: #ffffff;        /* primary boid color (bright) */
  --boid-accent: #00ffee; /* accent glow color */
  --trail: rgba(255,255,255,0.08);
}

/* Reset and ensure full-viewport layout */
html, body {
  height: 100%;
  width: 100%;
  margin: 0;
  padding: 0;
  background: var(--bg);
  color: var(--boid);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  overflow: hidden; /* prevent scrollbars when canvas is fullscreen */
}

/* Make the canvas fill the viewport and sit behind UI */
canvas, #canvas {
  position: fixed;
  inset: 0;               /* top:0; right:0; bottom:0; left:0; */
  width: 100vw;
  height: 100vh;
  display: block;
  background: var(--bg);
  z-index: 0;
}

/* If boids are DOM elements (fallback or UI debug), make them bright and glowing */
.boid, .boid-dot, .boid-marker {
  position: absolute;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background-color: var(--boid);
  box-shadow: 0 0 8px 2px var(--boid-accent), 0 0 18px var(--boid-accent);
  pointer-events: none;
  transform: translate(-50%, -50%);
  z-index: 10;
}

/* Optional trail elements if present */
.boid-trail {
  position: absolute;
  background: linear-gradient(0deg, var(--trail), transparent);
  pointer-events: none;
  z-index: 5;
}

/* High-DPI crispness helper for canvas-drawn boids */
canvas {
  image-rendering: optimizeSpeed;             /* Fast */
  image-rendering: -moz-crisp-edges;          /* Firefox */
  image-rendering: -o-crisp-edges;            /* Opera */
  image-rendering: -webkit-optimize-contrast; /* Webkit (non-standard) */
  image-rendering: crisp-edges;
}

/* UI overlay (controls, info) should appear above canvas */
.ui-overlay, .controls, .hud {
  position: relative;
  z-index: 20;
  color: var(--boid);
  background: transparent;
}

/* Accessibility: ensure focus outlines are visible on any interactive controls */
button:focus, a:focus, input:focus {
  outline: 2px solid rgba(255,255,255,0.12);
  outline-offset: 2px;
}

/* Reduced-motion preference: keep animations simple if user prefers */
@media (prefers-reduced-motion: reduce) {
  .boid, .boid-trail, canvas {
    transition: none !important;
    animation: none !important;
  }
}
"""

